from __future__ import annotations

from dataclasses import dataclass
from pathlib import Path

from ..entities import ApkArtifact, BuildMode
from ..repositories import (
    BuildRepository,
    LifecycleRepository,
    SessionStateRepository,
)
from ..result import Err, Result, ok
from .base import BaseUseCase
from ._helpers import resolve_serial


@dataclass(frozen=True, slots=True)
class BuildAppParams:
    project_path: Path
    mode: BuildMode = BuildMode.DEBUG
    flavor: str | None = None


class BuildApp(BaseUseCase[BuildAppParams, ApkArtifact]):
    def __init__(self, builds: BuildRepository) -> None:
        self._builds = builds

    async def execute(self, params: BuildAppParams) -> Result[ApkArtifact]:
        return await self._builds.build_apk(params.project_path, params.mode, params.flavor)


@dataclass(frozen=True, slots=True)
class InstallAppParams:
    apk_path: Path | None = None
    project_path: Path | None = None
    mode: BuildMode = BuildMode.DEBUG
    flavor: str | None = None
    serial: str | None = None


class InstallApp(BaseUseCase[InstallAppParams, ApkArtifact]):
    def __init__(
        self,
        builds: BuildRepository,
        lifecycle: LifecycleRepository,
        state: SessionStateRepository,
    ) -> None:
        self._builds = builds
        self._lifecycle = lifecycle
        self._state = state

    async def execute(self, params: InstallAppParams) -> Result[ApkArtifact]:
        serial_res = await resolve_serial(params.serial, self._state)
        if isinstance(serial_res, Err):
            return serial_res

        if params.apk_path is not None:
            apk = ApkArtifact(path=params.apk_path, mode=params.mode, flavor=params.flavor)
        elif params.project_path is not None:
            build_res = await self._builds.build_apk(
                params.project_path, params.mode, params.flavor
            )
            if isinstance(build_res, Err):
                return build_res
            apk = build_res.value
        else:
            from ..failures import InvalidArgumentFailure
            from ..result import err

            return err(
                InvalidArgumentFailure(
                    message="install requires either apk_path or project_path",
                )
            )

        install_res = await self._lifecycle.install(serial_res.value, apk.path)
        if isinstance(install_res, Err):
            return install_res
        return ok(apk)


@dataclass(frozen=True, slots=True)
class UninstallAppParams:
    package_id: str
    serial: str | None = None


class UninstallApp(BaseUseCase[UninstallAppParams, None]):
    def __init__(self, lifecycle: LifecycleRepository, state: SessionStateRepository) -> None:
        self._lifecycle = lifecycle
        self._state = state

    async def execute(self, params: UninstallAppParams) -> Result[None]:
        serial_res = await resolve_serial(params.serial, self._state)
        if isinstance(serial_res, Err):
            return serial_res
        return await self._lifecycle.uninstall(serial_res.value, params.package_id)

