class CompositeTestRepository(TestRepository):
    """Unit tests don't need a serial — delegate to Android (`flutter test` is platform-agnostic).
    Integration tests resolve platform from the serial."""

    def __init__(
        self,
        android: TestRepository,
        ios: TestRepository,
