"""Async wrapper around the `pymobiledevice3` CLI.

We shell out instead of using the Python API directly because pymobiledevice3's
public API surface is in flux across versions, while the CLI has been stable.
"""

from __future__ import annotations

from pathlib import Path

from .process_runner import ProcessResult, ProcessRunner


class PyMobileDevice3Cli:
    def __init__(self, runner: ProcessRunner, binary: str = "pymobiledevice3") -> None:
        self._runner = runner
        self._bin = binary

    async def usbmux_list(self, timeout_s: float = 10.0) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "usbmux", "list", "--no-color"], timeout_s=timeout_s
        )

    async def install(
        self, udid: str, bundle_path: Path, timeout_s: float = 300.0
    ) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "apps", "install", str(bundle_path), "--udid", udid],
            timeout_s=timeout_s,
        )

    async def uninstall(
        self, udid: str, bundle_id: str, timeout_s: float = 60.0
    ) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "apps", "uninstall", bundle_id, "--udid", udid],
            timeout_s=timeout_s,
        )

    async def launch(
        self, udid: str, bundle_id: str, timeout_s: float = 30.0
    ) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "developer", "dvt", "launch", bundle_id, "--udid", udid],
            timeout_s=timeout_s,
        )

    async def kill(
        self, udid: str, bundle_id: str, timeout_s: float = 15.0
    ) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "developer", "dvt", "kill", bundle_id, "--udid", udid],
            timeout_s=timeout_s,
        )

    async def screenshot(
        self, udid: str, output_path: Path, timeout_s: float = 30.0
    ) -> ProcessResult:
        return await self._runner.run(
            [self._bin, "developer", "screenshot", str(output_path), "--udid", udid],
            timeout_s=timeout_s,
        )

    async def syslog_collect(
        self, udid: str, output_path: Path, duration_s: int, timeout_s: float | None = None
    ) -> ProcessResult:
        return await self._runner.run(
            [
                self._bin,
                "syslog",
                "collect",
                str(output_path),
                "--udid",
                udid,
                "--timeout",
                str(duration_s),
            ],
            timeout_s=timeout_s or duration_s + 30,
        )

