"""ObservationRepository implementation for iOS.

- screenshot: pymobiledevice3 screenshot
- start/stop_recording: NOT SUPPORTED — iOS screen recording requires QuickTime / xrecord
  and isn't exposed by pymobiledevice3. Returns a typed Failure.
- read_logs / tail_logs_until: pymobiledevice3 syslog collect (best-effort)
"""

from __future__ import annotations

import asyncio
import re
from pathlib import Path

from ...domain.entities import LogEntry, LogLevel
from ...domain.failures import FilesystemFailure, FlutterCliFailure, TimeoutFailure
from ...domain.repositories import ObservationRepository
from ...domain.result import Result, err, ok
from ...infrastructure.pymobiledevice3_cli import PyMobileDevice3Cli


# Apple oslog severities mapped to our LogLevel.
_OSLOG_LEVEL = {
    "default": LogLevel.INFO,
    "info": LogLevel.INFO,
    "debug": LogLevel.DEBUG,
    "notice": LogLevel.INFO,
    "warn": LogLevel.WARN,
    "warning": LogLevel.WARN,
    "error": LogLevel.ERROR,
    "fault": LogLevel.FATAL,
}

_LEVEL_ORDER = {
    LogLevel.VERBOSE: 0,
    LogLevel.DEBUG: 1,
    LogLevel.INFO: 2,
    LogLevel.WARN: 3,
    LogLevel.ERROR: 4,
    LogLevel.FATAL: 5,
}


def _parse_oslog_line(line: str) -> LogEntry | None:
    """Parse a single os_log line. Format varies; we extract best-effort.

    Typical: `<timestamp> <pid> <level> <subsystem>: <message>`
    """
    parts = line.strip().split(None, 4)
    if len(parts) < 5:
        return None
    timestamp_a, timestamp_b, pid_s, level_token, rest = parts
    level = _OSLOG_LEVEL.get(level_token.lower(), LogLevel.INFO)
    if ":" in rest:
        tag, message = rest.split(":", 1)
        message = message.strip()
    else:
        tag, message = "ios", rest
    try:
        pid = int(pid_s)
    except ValueError:
        pid = None
    return LogEntry(
        timestamp=f"{timestamp_a} {timestamp_b}",
        level=level,
        tag=tag.strip(),
        pid=pid,
        message=message,
    )


class IosObservationRepository(ObservationRepository):
    def __init__(self, cli: PyMobileDevice3Cli) -> None:
        self._cli = cli

    async def screenshot(self, serial: str, output_path: Path) -> Result[Path]:
        output_path.parent.mkdir(parents=True, exist_ok=True)
        result = await self._cli.screenshot(serial, output_path)
        if not result.ok or not output_path.exists():
            return err(
                FlutterCliFailure(
                    message="iOS screenshot failed",
                    details={"stderr": result.stderr},
                )
            )
        return ok(output_path)

    async def start_recording(self, serial: str, output_path: Path) -> Result[None]:
        return err(
            FlutterCliFailure(
                message="iOS screen recording is not supported via pymobiledevice3",
                details={"workaround": "use Xcode/QuickTime or `xrecord`"},
            )
        )

    async def stop_recording(self, serial: str) -> Result[Path]:
        return err(
            FlutterCliFailure(
                message="iOS screen recording is not supported via pymobiledevice3"
            )
        )

    async def read_logs(
        self,
        serial: str,
        since_s: int = 30,
        tag: str | None = None,
        min_level: LogLevel = LogLevel.WARN,
        max_lines: int = 500,
    ) -> Result[list[LogEntry]]:
        # pymobiledevice3 syslog collect writes to a file; use a temp file.
        import tempfile

        with tempfile.NamedTemporaryFile(suffix=".log", delete=False) as tmp:
            tmp_path = Path(tmp.name)
        try:
            result = await self._cli.syslog_collect(serial, tmp_path, duration_s=since_s)
            if not result.ok:
                return err(
                    FlutterCliFailure(
                        message="syslog collect failed",
                        details={"stderr": result.stderr},
                    )
                )
            try:
                text = tmp_path.read_text(errors="replace")
            except OSError as e:
                return err(FilesystemFailure(message=f"failed to read syslog: {e}"))
            entries: list[LogEntry] = []
            threshold = _LEVEL_ORDER[min_level]
            for raw in text.splitlines():
                entry = _parse_oslog_line(raw)
                if entry is None:
                    continue
                if _LEVEL_ORDER[entry.level] < threshold:
                    continue
                if tag is not None and entry.tag != tag:
                    continue
                entries.append(entry)
                if len(entries) >= max_lines:
                    break
            return ok(entries[-max_lines:])
        finally:
            tmp_path.unlink(missing_ok=True)

    async def tail_logs_until(
        self,
        serial: str,
        until_pattern: str,
        tag: str | None = None,
        timeout_s: float = 30.0,
    ) -> Result[list[LogEntry]]:
        # Approximation: collect for `timeout_s` seconds, then scan for the pattern.
        # A true streaming implementation would subprocess-pipe `pymobiledevice3 syslog live`,
        # which is left as a follow-up given API churn in pymobiledevice3 across versions.
        pattern = re.compile(until_pattern)
        collected_res = await self.read_logs(
            serial, since_s=int(timeout_s), tag=tag, min_level=LogLevel.VERBOSE, max_lines=10000
        )
        if collected_res.is_err:
            return collected_res  # type: ignore[return-value]
        for entry in collected_res.value:  # type: ignore[union-attr]
            if pattern.search(entry.message):
                return ok(collected_res.value)  # type: ignore[union-attr]
        return err(
            TimeoutFailure(
                message="tail_logs_until: pattern not seen in collected window",
                details={"pattern": until_pattern, "timeout_s": timeout_s},
            )
        )

